const CATEGORIES = [
  'All Categories',
  'Electronics',
  'Clothing',
  'Food & Beverages',
  'Home & Garden',
  'Health & Beauty',
  'Sports & Outdoors',
  'Books & Media',
  'Automotive',
];

export default function Browse() {
  const [selectedCategory, setSelectedCategory] = useState('All Categories');
  const [products, setProducts] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [loadError, setLoadError] = useState(null);
  const { addToCart, cartCount } = useAppContext();
  const navigate = useNavigate();

  useEffect(() => {
    let mounted = true;
    async function loadProducts() {
      setIsLoading(true);
      setLoadError(null);
      try {
        const data = await fetchProducts({ perPage: 100 });
        if (!mounted) return;
        setProducts(Array.isArray(data) ? data : data?.data || []);
      } catch (error) {
        console.error(error);
        if (mounted) {
          setLoadError('Unable to load products from the API. Showing sample products.');
        }
      } finally {
        if (mounted) setIsLoading(false);
      }
    }

    loadProducts();
    return () => { mounted = false; };
  }, []);

  const normalizedProducts = (products.length ? products : MOCK_PRODUCTS).map(product => ({
    id: product.id,
    name: product.title || product.name,
    price: product.price || product.amount || 0,
    seller: product.seller?.businessName || product.seller || 'Seller',
    location: product.location || product.seller?.location || 'Lilongwe',
    category: product.category?.name || product.category || 'General',
    image: product.image || getCategoryImage(product.title || product.name, product.category?.name || product.category || 'General'),
    condition: 'New',
    inStock: product.stock == null || product.stock > 0,
    rating: product.rating || 4.5,
    reviews: product.reviews || 0,
  }));

  const cartItemCount = cartCount;

  const filteredProducts =
    selectedCategory === 'All Categories'
      ? normalizedProducts
      : normalizedProducts.filter(p => p.category === selectedCategory);

  const groupedProducts = {};
  if (selectedCategory === 'All Categories') {
    filteredProducts.forEach(product => {
      if (!groupedProducts[product.category]) groupedProducts[product.category] = [];
      groupedProducts[product.category].push(product);
    });
  } else {
    groupedProducts[selectedCategory] = filteredProducts;
  }

  const handleAddToCart = (productId) => {
    const product = normalizedProducts.find(p => p.id === productId);
    if (!product) return;
    addToCart(product, 1);
  };

  const handleViewDetails = (productId) => {
    navigate(`/product/${productId}`);
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="mb-8">
          <div className="flex items-center gap-3 mb-6">
            <Grid3x3 className="text-accent" size={32} />
            <h1 className="text-4xl font-bold text-gray-900">Browse Products</h1>
          </div>
          <div className="flex items-center gap-4">
            <label className="text-sm font-semibold text-gray-700">Filter by Category:</label>
            <select
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value)}
              className="px-4 py-2 border-2 border-gray-300 rounded-lg focus:ring-2 focus:ring-accent focus:border-transparent outline-none bg-white cursor-pointer"
            >
              {CATEGORIES.map(cat => <option key={cat} value={cat}>{cat}</option>)}
            </select>
            <span className="text-sm text-gray-500">
              ({filteredProducts.length} product{filteredProducts.length !== 1 ? 's' : ''})
              {cartItemCount > 0 && ` • ${cartItemCount} item${cartItemCount !== 1 ? 's' : ''} in cart`}
            </span>
          </div>
          {loadError && (
            <div className="mt-4 rounded-lg bg-yellow-50 border border-yellow-200 p-4 text-yellow-700">
              {loadError}
            </div>
          )}
          {isLoading && (
            <div className="mt-4 rounded-lg bg-white border border-gray-200 p-4 text-gray-600">
              Loading products from the API...
            </div>
          )}
        </div>

        {Object.entries(groupedProducts).map(([category, products]) => (
          <div key={category} className="mb-12">
            <h2 className="text-2xl font-bold text-gray-900 mb-6 pb-4 border-b-2 border-accent">{category}</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
              {products.map(product => {
                const productWithImage = { ...product, image: getCategoryImage(product.name, product.category), condition: 'New', inStock: true };
                return (
                  <ProductCard
                    key={product.id}
                    product={productWithImage}
                    onAddToCart={handleAddToCart}
                    onViewDetails={handleViewDetails}
                  />
                );
              })}
            </div>
          </div>
        ))}

        {filteredProducts.length === 0 && (
          <div className="text-center py-12">
            <p className="text-gray-500 text-lg">No products found in this category.</p>
          </div>
        )}
      </div>
    </div>
  );
}
